import '@testing-library/jest-native/extend-expect';

jest.mock(
  '~/store',
  () => ({
    useRootStore: Object.assign(jest.fn(), { getState: jest.fn() }),
  }),
  { virtual: true },
);

jest.mock(
  '~/constants/functions',
  () => ({
    eventSelectContent: jest.fn(),
  }),
  { virtual: true },
);

jest.mock('@semparar/mf-app-user', () => ({
  api: {
    get: jest.fn(),
    post: jest.fn(),
  },
}));

jest.mock('zustand/shallow', () => ({
  useShallow: selector => selector,
}));

jest.mock(
  '~/redux/store/storage',
  () => ({
    storage: {
      getItem: jest.fn(),
      setItem: jest.fn(),
      removeItem: jest.fn(),
    },
  }),
  { virtual: true },
);

jest.mock('@react-native-community/slider', () => 'Slider', { virtual: true });

jest.mock('react-native-safe-area-context', () => {
  const React = require('react');
  const { View } = require('react-native');
  return {
    SafeAreaProvider: ({ children }) =>
      React.createElement(View, { testID: 'safe-area-provider' }, children),
    SafeAreaView: ({ children }) =>
      React.createElement(View, { testID: 'safe-area-view' }, children),
    useSafeAreaInsets: () => ({
      top: 0,
      bottom: 0,
      left: 0,
      right: 0,
    }),
    useSafeAreaFrame: () => ({
      width: 375,
      height: 812,
      x: 0,
      y: 0,
    }),
    SafeAreaInsetsContext: {
      Consumer: ({ children }) =>
        children({
          top: 0,
          bottom: 0,
          left: 0,
          right: 0,
        }),
    },
  };
});

jest.mock('react-native/Libraries/Settings/Settings', () => ({
  get: jest.fn(),
  set: jest.fn(),
}));

jest.mock('react-native/Libraries/TurboModule/TurboModuleRegistry', () => ({
  get: jest.fn(() => null),
  getEnforcing: jest.fn(moduleName => {
    if (moduleName === 'StatusBarManager') {
      return {
        getConstants: jest.fn(() => ({
          HEIGHT: 44,
          DEFAULT_BACKGROUND_COLOR: 0,
        })),
        setStyle: jest.fn(),
        setHidden: jest.fn(),
        getHeight: jest.fn(cb => cb({ height: 44 })),
        setNetworkActivityIndicatorVisible: jest.fn(),
        addListener: jest.fn(),
        removeListeners: jest.fn(),
        setBackgroundColor: jest.fn(),
        setTranslucent: jest.fn(),
      };
    }
    return {
      getConstants: jest.fn(() => ({
        Dimensions: {
          window: {
            width: 375,
            height: 812,
          },
          screen: {
            width: 375,
            height: 812,
          },
        },
      })),
      addListener: jest.fn(),
      removeListeners: jest.fn(),
    };
  }),
}));

jest.mock('react-native/Libraries/Utilities/NativeDeviceInfo', () => ({
  getConstants: jest.fn(() => ({
    Dimensions: {
      window: {
        width: 375,
        height: 812,
        scale: 2,
        fontScale: 1,
      },
      screen: {
        width: 375,
        height: 812,
        scale: 2,
        fontScale: 1,
      },
    },
  })),
}));

jest.mock('react-native/Libraries/EventEmitter/NativeEventEmitter');

jest.mock('react-native-reanimated', () =>
  require('react-native-reanimated/mock'));

const createModalizeMock = () => {
  const React = require('react');
  const { View } = require('react-native');
  return React.forwardRef(({ children }, ref) => {
    React.useImperativeHandle(ref, () => ({
      open: jest.fn(),
      close: jest.fn(),
    }));
    return React.createElement(View, { testID: 'modalize' }, children);
  });
};

jest.mock('react-native-modalize', () => ({ Modalize: createModalizeMock() }), {
  virtual: true,
});

jest.mock('@semparar/design-system-app/src/atomic/atoms/Modalize/view', () => ({
  __esModule: true,
  default: createModalizeMock(),
}));

jest.mock('lottie-react-native', () => 'LottieView', { virtual: true });

jest.mock('react-native-video', () => 'Video', { virtual: true });

jest.mock(
  'react-native-skeleton-placeholder',
  () => {
    const React = require('react');
    const SkeletonPlaceholder = ({ children }) =>
      React.createElement('View', { testID: 'skeleton-placeholder' }, children);
    SkeletonPlaceholder.Item = ({ children }) =>
      React.createElement('View', { testID: 'skeleton-item' }, children);
    return SkeletonPlaceholder;
  },
  { virtual: true },
);

jest.mock(
  'react-native-linear-gradient',
  () => {
    const { View } = require('react-native');
    return View;
  },
  { virtual: true },
);

jest.mock(
  'react-native-svg',
  () => {
    const React = require('react');
    const createMockComponent = name => {
      const Component = props =>
        React.createElement('View', {
          ...props,
          testID: name,
        });
      Component.displayName = name;
      return Component;
    };
    return {
      Svg: createMockComponent('Svg'),
      Circle: createMockComponent('Circle'),
      Ellipse: createMockComponent('Ellipse'),
      G: createMockComponent('G'),
      Text: createMockComponent('SvgText'),
      TSpan: createMockComponent('TSpan'),
      TextPath: createMockComponent('TextPath'),
      Path: createMockComponent('Path'),
      Polygon: createMockComponent('Polygon'),
      Polyline: createMockComponent('Polyline'),
      Line: createMockComponent('Line'),
      Rect: createMockComponent('Rect'),
      Use: createMockComponent('Use'),
      Image: createMockComponent('SvgImage'),
      Symbol: createMockComponent('Symbol'),
      Defs: createMockComponent('Defs'),
      LinearGradient: createMockComponent('LinearGradient'),
      RadialGradient: createMockComponent('RadialGradient'),
      Stop: createMockComponent('Stop'),
      ClipPath: createMockComponent('ClipPath'),
      Pattern: createMockComponent('Pattern'),
      Mask: createMockComponent('Mask'),
      default: createMockComponent('Svg'),
    };
  },
  { virtual: true },
);

jest.mock(
  'react-native-gesture-handler',
  () => {
    const View = require('react-native').View;
    return {
      Swipeable: View,
      DrawerLayout: View,
      State: {},
      ScrollView: View,
      Slider: View,
      Switch: View,
      TextInput: View,
      ToolbarAndroid: View,
      ViewPagerAndroid: View,
      DrawerLayoutAndroid: View,
      WebView: View,
      NativeViewGestureHandler: View,
      TapGestureHandler: View,
      FlingGestureHandler: View,
      ForceTouchGestureHandler: View,
      LongPressGestureHandler: View,
      PanGestureHandler: View,
      PinchGestureHandler: View,
      RotationGestureHandler: View,
      RawButton: View,
      BaseButton: View,
      RectButton: View,
      BorderlessButton: View,
      FlatList: View,
      gestureHandlerRootHOC: jest.fn(component => component),
      Directions: {},
      GestureDetector: View,
      Gesture: {
        Pan: jest.fn(() => ({})),
        Tap: jest.fn(() => ({})),
      },
    };
  },
  { virtual: true },
);

